// HasTenant applies the HasEdge predicate on the "tenant" edge.
func HasTenant() predicate.DiagnosisAuthTicket {
	return predicate.DiagnosisAuthTicket(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.M2O, false, TenantTable, TenantColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasTenantWith applies the HasEdge predicate on the "tenant" edge with a given conditions (other predicates).
func HasTenantWith(preds ...predicate.Tenant) predicate.DiagnosisAuthTicket {
	return predicate.DiagnosisAuthTicket(func(s *sql.Selector) {
		step := newTenantStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// And groups predicates with the AND operator between them.
func And(predicates ...predicate.DiagnosisAuthTicket) predicate.DiagnosisAuthTicket {
	return predicate.DiagnosisAuthTicket(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.DiagnosisAuthTicket) predicate.DiagnosisAuthTicket {
	return predicate.DiagnosisAuthTicket(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.DiagnosisAuthTicket) predicate.DiagnosisAuthTicket {
	return predicate.DiagnosisAuthTicket(sql.NotPredicates(p))
}
